/* factions q08 (66 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q08"]=window.__LIBQ["tien-nghich"]["q08"]||{};window.__LIBQ["tien-nghich"]["q08"]["factions"]={"updatedAt":"2026-07-11","count":66,"factions":[{"id":"the-luc-cua-thanh-thuy","name":"Thế lực của Thanh Thủy","cn":"","type":"khac","typeLabel":"Uy thế cá nhân","diaBan":"không rõ","nhanVatChinh":["Thanh Thủy","Vương Lâm","Liệt Vân Tử"],"blurb":"Uy thế gắn với Thanh Thủy từng được Vương Lâm mượn để áp chế Liệt Vân Tử. Việc này khiến Liệt Vân Tử đánh giá Vương Lâm không đơn giản.","detail":"Trong suy nghĩ của Liệt Vân Tử, Vương Lâm từng có thể mượn thế lực của Thanh Thủy để áp chế lão. Thế lực này được nhắc như một dạng uy thế cá nhân đủ khiến Liệt Vân Tử kiêng dè.","nguon":["@c0889"]},{"id":"tu-si-sat-vuc-gioi-the-luc","name":"Tu sĩ Sát Vực giới","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ","diaBan":"Sát Vực giới","nhanVatChinh":["Huyễn Hư Tử","Thần Ma Tử","Tu sĩ Sát Vực giới"],"blurb":"Nhóm tu sĩ thuộc Sát Vực giới tham chiến quanh nơi Vương Lâm đoạt kiếm. Họ bị Tát Đậu Thành Binh và lôi đình vây khốn, sau đó có người chết vì dư ba giao phong cấp Tịnh Niết.","detail":"Trong chương 893, tu sĩ Sát Vực giới hiện diện đông quanh chiến trường nhưng không thể ngăn Vương Lâm thu kiếm do bị thần thông và lôi đình kiềm chế. Khi Huyễn Hư Tử và Vương Lâm đối oanh bằng thần thông Tịnh Niết và Cổ Thần lực, một số người không tránh kịp bị gió lốc cuốn thành sương máu.","nguon":["@c0893"]},{"id":"tong-bo-lien-minh","name":"Tổng bộ Liên Minh","cn":"","type":"lien-minh","typeLabel":"Thế lực","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Tổng bộ Liên Minh được nhắc trong lúc Lăng Vân Tử cân nhắc tình thế của Sát Vực Giới. Phần lớn Tịnh Niết tu sĩ đã tới nơi này, khiến hắn thiếu người thi triển kiếm trận.","detail":"Trong chương Sát Vực Giới bị Thanh Thủy công phá, giới chủ Sát Vực Giới nghĩ tới việc nhiều Tịnh Niết tu sĩ đã đi tới Tổng bộ Liên Minh. Việc thiếu lực lượng khiến hắn không đủ điều kiện thi triển chín mươi chín kiếm trận để đối kháng Thanh Thủy.","nguon":["@c0894"]},{"id":"lam-he-thien-van-tong","name":"Lam hệ Thiên Vận Tông","cn":"","type":"chi-he","typeLabel":"Chi hệ tông môn","diaBan":"Thiên Vận Tông","nhanVatChinh":["Tư Mã Như Phong"],"blurb":"Lam hệ là một chi hệ trong Thiên Vận Tông, được nhắc qua thân phận của Tư Mã Như Phong.","detail":"Tư Mã Như Phong được xác định là Lam hệ đệ tử. Chương nhắc lại hắn từng tham gia việc vây khốn Vương Lâm cùng tứ sư tỷ Tử hệ.","nguon":["@c0898"]},{"id":"tu-ha-tinh","name":"Tử Hà Tinh","cn":"","type":"the-luc","typeLabel":"Địa bàn luyện khí","diaBan":"Tử Hà Tinh","nhanVatChinh":["Mỹ phụ thôn nữ trung niên","Phấn y nữ nhân","Thiên Cầm cô nương"],"blurb":"Tử Hà Tinh là địa bàn liên quan mỹ phụ luyện khí tông sư và nhóm nữ tu đi cùng bà. Sau khi nhận ra phi kiếm của Vương Lâm sát khí quá nặng, mỹ phụ mời hắn tới Tử Hà Tinh.","detail":"Trong buổi các lão quái chứng kiến Vương Lâm giao chiến với Lăng Thiên Hậu, mỹ phụ luyện khí từ Tử Hà Tinh nhận ra chất liệu và sát khí phi kiếm của Vương Lâm rất bất phàm. Khi rời đi, bà mời hắn tới Tử Hà Tinh nếu có thời gian, cho thấy nơi này gắn với năng lực luyện khí và xử lý pháp bảo.","nguon":["@c0899"]},{"id":"mong-tinh","name":"Mộng Tinh","cn":"","type":"the-luc","typeLabel":"Địa bàn của Kỳ Mộng Đàm","diaBan":"Mộng Tinh","nhanVatChinh":["Kỳ Mộng Đàm"],"blurb":"Mộng Tinh là địa bàn của Kỳ Mộng Đàm. Sau khi chứng kiến thực lực Vương Lâm, ông mời hắn tới Mộng Tinh chơi.","detail":"Kỳ Mộng Đàm tự xưng khi rời khỏi Thiên Vận Tông và nói nếu có thời gian thì mời Vương Lâm tới Mộng Tinh của mình. Lời mời này xuất hiện sau khi ông chứng kiến Vương Lâm dùng kiếm trận chống Lăng Thiên Hậu và nhận ra đối phương không tầm thường.","nguon":["@c0899"]},{"id":"quy-nhan-phuong-thi","name":"Quỷ Nhãn phường thị","cn":"","type":"phuong-thi","typeLabel":"Phường thị giao dịch","diaBan":"không rõ","nhanVatChinh":["Lý sư huynh","Sư muội của Lý sư huynh"],"blurb":"Phường thị sắp mở lại sau bảy ngày, từng nổi danh vì bán đấu giá một đạo tiên thuật đầy đủ. Nơi này có khu đấu giá cần tư cách và khu giao dịch tự do bên ngoài.","detail":"Quỷ Nhãn phường thị được hai đệ tử Thiên Vận Tông nhắc tới trên đường Tử hệ. Phường thị từng gây chấn động vì đấu giá tiên thuật đầy đủ, lần mở lại này nghe nói cũng có vật thần bí, khiến Lý sư huynh đặc biệt chú ý tới cơ hội ở khu giao dịch bên ngoài.","nguon":["@c0900"]},{"id":"that-he-thien-van-tong","name":"Thất hệ Thiên Vận Tông","cn":"","type":"tong-mon","typeLabel":"Cơ cấu tông môn","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Triệu Hân Mộng","Tôn Hồng","Lô Hải","Nhất Tử"],"blurb":"Thất hệ Thiên Vận Tông là cơ cấu các hệ đệ tử đích truyền trong tông. Chương này hé lộ trong thất hệ có nhiều người che giấu tu vi và không ai công khai đạt Âm Hư.","detail":"Triệu Hân Mộng nói ngay cả đệ tử đích truyền trong thất hệ cũng không ai công khai vượt Vấn Đỉnh lên Âm Hư, vì người đạt tới mức đó có thể mất tích trong vòng một năm. Nàng nêu các trường hợp Tôn Hồng Xích hệ, Lô Hải Hồng hệ và Nhất Tử Cam hệ để cho thấy việc phong ấn tu vi lan rộng trong nội bộ.","nguon":["@c0902"]},{"id":"xich-he","name":"Xích hệ","cn":"","type":"he-phai","typeLabel":"Hệ phái Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Tôn Hồng"],"blurb":"Xích hệ là một hệ phái trong Thiên Vận Tông. Tôn Hồng thuộc Xích hệ được Triệu Hân Mộng nói là người che giấu tu vi sâu nhất mà nàng biết.","detail":"Trong lời kể của Triệu Hân Mộng, Xích hệ gắn với Tôn Hồng, người có mười một đạo phong ấn trong cơ thể. Trường hợp này cho thấy đệ tử trong các hệ Thiên Vận Tông có thể tự áp chế tu vi để tránh cấm kỵ mất tích.","nguon":["@c0902"]},{"id":"hong-he","name":"Hồng hệ","cn":"","type":"he-phai","typeLabel":"Hệ phái Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Lô Hải"],"blurb":"Hồng hệ là một hệ phái trong Thiên Vận Tông. Lô Hải thuộc Hồng hệ được nhắc là người nếu mở phong ấn sẽ đạt Dương Thực đỉnh.","detail":"Triệu Hân Mộng nêu Lô Hải của Hồng hệ như một ví dụ khác về đệ tử che giấu tu vi thật. Nếu cởi bỏ phong ấn, tu vi của hắn được nói sẽ lập tức là Dương Thực đỉnh.","nguon":["@c0902"]},{"id":"cam-he","name":"Cam hệ","cn":"","type":"he-phai","typeLabel":"Hệ phái Thiên Vận Tông","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Nhất Tử"],"blurb":"Cam hệ là một hệ phái trong Thiên Vận Tông. Nhất Tử thuộc Cam hệ từng mở phong ấn do chạm cực hạn rồi mất tích.","detail":"Theo lời Triệu Hân Mộng, năm trăm năm trước Nhất Tử của Cam hệ buộc phải mở phong ấn trong cơ thể và ngay sau đó biến mất. Trường hợp này trở thành tiền lệ cụ thể cho nỗi sợ của các đệ tử che giấu tu vi.","nguon":["@c0902"]},{"id":"tran-dao-tam-tu","name":"Trần Đạo Tam Tử","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ","diaBan":"Quỷ Nhãn Thành","nhanVatChinh":["Trần Nhất Tử","Âu Dương Tử"],"blurb":"Ba tu sĩ phụ trách an toàn bên trong Quỷ Nhãn Thành, dùng thần thức hợp lực ngăn và định phế thần thức người dò xét thành.","detail":"Trần Đạo Tam Tử nhận đại lễ của Quỷ Nhãn Thành để giữ an toàn cho đợt mở thành. Ba đạo thần thức của họ hợp lực vây thần thức Vương Lâm, một người tự xưng Trần Nhất Tử, một đạt Khuy Niết trung kỳ là Âu Dương Tử. Họ ép Vương Lâm nhận sai rời đi nhưng bị hắn phá cấm phản kích.","nguon":["@c0904"]},{"id":"quy-nhan-thanh","name":"Quỷ Nhãn Thành","cn":"","type":"to-chuc","typeLabel":"Tổ chức giao dịch","diaBan":"Thiên Vận Tinh","nhanVatChinh":["Trần Nhất Tử","Lão nhân áo xanh uy nghiêm"],"blurb":"Địa điểm mở đấu giá và tự do giao dịch, trao đại lễ cho Trần Đạo Tam Tử phụ trách an toàn, có quy củ hạn chế thần thức dò xét.","detail":"Quỷ Nhãn Thành nổi danh vì từng bán đấu giá một bộ tiên thuật đầy đủ, mỗi tháng mở thành có khu đấu giá cùng khu tự do giao dịch. Thành có cấm chế nghiêm và lực lượng bảo an mạnh do Trần Đạo Tam Tử đảm nhận, sẵn sàng phế thần thức người dò xét.","nguon":["@c0904"]},{"id":"thien-van-tu-lang-thien-hau-doi-nghich-lau-nam","name":"Thiên Vận Tử - Lăng Thiên Hậu đối nghịch lâu năm","cn":"","type":"quan-he","typeLabel":"Quan hệ đối nghịch","diaBan":"không rõ","nhanVatChinh":["Thiên Vận Tử","Lăng Thiên Hậu"],"blurb":"Quan hệ đối nghịch kéo dài mấy vạn năm giữa Thiên Vận Tử và Lăng Thiên Hậu.","detail":"Chương này nhấn mạnh Lăng Thiên Hậu đã đối nghịch Thiên Vận Tử mấy vạn năm dù chênh lệch tu vi rất lớn. Thiên Vận Tử còn trách Lăng Thiên Hậu không tuân theo ước định, cho thấy giữa hai người tồn tại bí mật chưa hé lộ.","nguon":["@c0913"]},{"id":"tu-chan-tong-con-hu","name":"Tu chân tông Côn Hư","cn":"","type":"tong-mon","typeLabel":"Nước tu chân cấp chín","diaBan":"Côn Hư địa vực trong Liên minh Tinh vực","nhanVatChinh":["Hư Linh thượng nhân"],"blurb":"Tu chân tông Côn Hư là nước tu chân cấp chín duy nhất trong Liên minh Tinh vực. Thế lực này giữ danh xưng Côn Hư cổ xưa, có uy vọng rất cao trong mắt tu sĩ cấp cao.","detail":"Lăng Thiên Hậu giải thích rằng Côn Hư không chỉ là tên cổ của tinh vực mà còn là một tu chân tông quốc cấp chín duy nhất trong Liên minh Tinh vực. Tu sĩ cấp cao có thể bất kính Tu Chân Liên Minh nhưng vẫn kính trọng Côn Hư; cứ ba ngàn năm Côn Hư phát ba thiệp mời cho người vào Côn Hư địa vực tu luyện. Lăng Thiên Hậu và Thiên Vận tử từng được mời, còn Hư Linh thượng nhân của Côn Hư từng luyện hóa mảnh vỡ hư tinh thành Đại La tinh.","nguon":["@c0915"]},{"id":"thanh-long-thanh-tong","name":"Thanh Long Thánh Tông","cn":"青龍聖宗","type":"tong-mon","typeLabel":"Thánh tông","diaBan":"chưa rõ","nhanVatChinh":["Thanh Long Thánh Hoàng","Chín lão già Thanh Long Thánh tông"],"blurb":"Thanh Long Thánh Tông là một trong các thế lực thuộc hệ Tứ Thánh Tông, được Vương Lâm suy đoán có liên hệ với mảnh vỡ khắc thanh long trong Thanh quang thuẫn. Tông môn nắm giữ Thanh Long thánh khí và từng được Thần niệm Thanh Long Thánh Hoàng chỉ định là nơi cần truyền tin báo.","detail":"Sau khi thu được mảnh vỡ khắc thanh long và nhận thấy khí tức giống ấn ký Chu Tước, Vương Lâm liên hệ nó với Thanh Long Thánh Tông trong hệ Tứ Thánh Tông. Thần niệm Thanh Long Thánh Hoàng nêu rõ nếu không tới cứu thì hãy truyền tin cho Thanh Long Thánh Tông. Trong tiến trình, chín lão già của thế lực nàyra mắt Chu Tước Thánh Hoàng và đồng ý giao thánh khí thái cổ, sau đó Thanh Long Thánh Tông triệu Thanh Long thánh khí phối hợp cùng tứ thánh khí trong trận thế.","nguon":["@c0923","@c1008","@c1013"],"tabs":{"tienTrinh":[{"chuong":"@c1008","loai":"lien-minh","importance":"major","trangThaiMoc":"Phục tùng Chu Tước Thánh Hoàng","giaiDoan":"Giao thánh khí, nghe lệnh","text":"Chín lão già bay ra khỏi sương xanh, cung kính ra mắt Chu Tước Thánh Hoàng, đồng ý giao thánh khí thái cổ và đi theo phục vụ thức tỉnh Chu Tước.","anchor":"Chu Tước Thánh Hoàng có lệnh, chúng ta xin nghe theo!"},{"chuong":"@c1013","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","trangThaiMoc":"hoat-dong","text":"Thanh Long Thánh Tông triệu Thanh Long thánh khí hóa Thanh Long khổng lồ phương Đông, phối hợp tứ thánh khí hợp nhất tấn công Cổ Ma Tháp Già và Thiên Vận Tử.","anchor":"Vị lão già mặc quần áo có thêu chín con Thanh Long thở dài"}]},"thanhVien":[{"ten":"Lão già y phục thêu chín Thanh Long","chucVu":"Đại diện thi triển thánh khí","tuChuong":"@c1013","trangThai":"hoat-dong"}],"uyLuc":"Triệu Thanh Long thánh khí hóa thành Thanh Long khổng lồ trấn phương Đông, phối hợp cùng tứ thánh khí trong trận thế (@c1013)","dacDiem":"Thế lực thuộc hệ Tứ Thánh Tông, nắm giữ Thanh Long thánh khí và thánh khí thái cổ","congNang":["Chín lão già cung kính ra mắt Chu Tước Thánh Hoàng, đồng ý giao thánh khí thái cổ (@c1008)","Triệu Thanh Long thánh khí hóaành Thanh Long khổng lồ phương Đông, phối hợp cùng tứ thánh khí (@c1013)"]},{"id":"phan-hong-cung","name":"Phấn Hồng Cung","cn":"","type":"tong-mon","typeLabel":"Thế lực","diaBan":"gần hướng Thiên Vận Tinh","nhanVatChinh":["Nữ tử Phấn Hồng Cung đi cùng Tư Đồ Nam"],"blurb":"Phấn Hồng Cung là thế lực được nữ tử đi cùng Tư Đồ Nam nhắc tới trên đường tới Thiên Vận Tinh. Nơi này được giới thiệu có các tỷ muội mỹ nhân khiến Tư Đồ Nam hứng thú.","detail":"Trong chương này, Phấn Hồng Cung là mục tiêu Tư Đồ Nam đang đi tới xem. Nữ tử đồng hành khẳng định các tỷ muội trong cung đều là mỹ nhân và mong Tư Đồ Nam sau khi vừa lòng thì đừng quên Phấn Hồng Cung.","nguon":["@c0925"]},{"id":"hai-nguc-gioi-faction","name":"Hài Ngục Giới","cn":"","type":"the-luc","typeLabel":"Nguồn luyện thi","diaBan":"không rõ","nhanVatChinh":["Nữ luyện thi áo bạc của Hài Ngục Giới"],"blurb":"Hài Ngục Giới được nhắc như nguồn gốc của các luyện thi mà phía Liên Minh từng lấy được. Nữ luyện thi áo bạc trong tay Vương Lâm bắt nguồn từ nơi này.","detail":"Trong bối cảnh Vương Lâm lấy nữ luyện thi áo bạc ra, chương nêu luyện thi này thuộc loại mà Liên Minh từng thu được từ Hài Ngục Giới. Điều này đặt Hài Ngục Giới vào vai trò nguồn gốc của vật luyện thi có chiến lực đáng kể.","nguon":["@c0925"]},{"id":"nguyet-toc-thai-co","name":"Nguyệt tộc Thái cổ","cn":"","type":"toc-dan","typeLabel":"Tộc đàn Thái cổ","diaBan":"","nhanVatChinh":["Linh nhi"],"blurb":"Tộc đàn Thái cổ của Mộc Linh (Linh nhi) trong ảo cảnh luân hồi, có nghi lễ dâng thiên địa lực cho Cổ Thần qua Thần nô.","detail":"Nguyệt tộc Thái cổ là tộc của Thần nô Mộc Linh trong ký ức luân hồi. Dân chúng tộc này mang dấu ấn trăng sáng trên mi tâm, có nghi lễ ngưng tụ thiên địa lực đưa vào bảo bình của Thần nô để dâng lên Cổ Thần, đổi lấy thần lực chinh chiến Tháp tộc.","nguon":["@c0927"]},{"id":"thap-toc","name":"Tháp tộc","cn":"","type":"toc-dan","typeLabel":"Tộc đàn đối địch","diaBan":"","nhanVatChinh":[],"blurb":"Tộc đàn đối địch được nhắc là mục tiêu chinh chiến của Nguyệt tộc Thái cổ.","detail":"Tháp tộc được nêu trong lời khẩn cầu của Mộc Linh, là tộc mà Nguyệt tộc Thái cổ muốn mượn thần lực Cổ Thần để chinh chiến.","nguon":["@c0927"]},{"id":"cu-ma-tinh","name":"Cự Ma tinh","cn":"","aliases":[],"type":"dia-ban-the-luc","typeLabel":"Địa bàn liên quan thế lực","diaBan":"Cự Ma tinh","nhanVatChinh":["Lôi Cát","Vương Lâm"],"blurb":"Mục tiêu mà Lôi Cát muốn thu hồi trong tuyến Cự Ma tộc.","detail":"Sau khi chứng kiến sức mạnh của Vương Lâm, Lôi Cát tin rằng chủ nhân càng mạnh thì hắn càng có nắm chắc thu hồi Cự Ma tinh.","nguon":["@c0930"]},{"id":"hong-phan-cung","name":"Hồng Phấn cung","cn":"","type":"tong-mon","typeLabel":"Thế lực","diaBan":"Thiên Vận tinh","nhanVatChinh":["Tư Đồ Nam"],"blurb":"Thế lực do Tư Đồ Nam làm cung chủ trên Thiên Vận tinh, tụ tập nhiều nữ tu bằng đan dược và tiên thuật.","detail":"Trong ba tháng, Tư Đồ Nam dựa vào tu vi Tịnh Niết, đan dược và tiên thuật để hấp dẫn nữ tu từ nhiều môn phái, khiến Hồng Phấn cung ngày càng đông và danh tiếng ham mê sắc đẹp lan rộng.","lanhDaoHienThoi":"Tư Đồ Nam","trangThai":"đang mở rộng","thanhVien":[{"ten":"Tư Đồ Nam","chucVu":"cung chủ","tuChuong":"@c0931","trangThai":"đương nhiệm"}],"lanhDaoMoc":[{"ten":"Tư Đồ Nam","tuChuong":"@c0931","denChuong":""}],"capNhatToi":"@c0931","tabs":{"tienTrinh":[]},"nguon":["@c0931"]},{"id":"phuong-loan-tinh-nu-tu","name":"Phượng Loan tinh nữ tu","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ","diaBan":"Phượng Loan tinh","nhanVatChinh":["Các nữ tu Phượng Loan tinh","Tư Đồ Nam"],"blurb":"Nhóm nữ tu trên Phượng Loan tinh từng truy sát và hạ độc Tư Đồ Nam.","detail":"Các nữ tu Phượng Loan tinh truy sát Tư Đồ Nam sau chuyện hắn gây họa ở nơi này, khiến hắn trúng Dục Tiên Dục Tử và phải trốn đông trốn tây. Theo lời Tư Đồ Nam, Phượng Loan tinh không có Toái Niết, cao nhất là Tịnh Niết trung kỳ, nhưng có hơn mười Tịnh Niết và còn có viện thủ ngoài tinh.","quanHe":"Là mục tiêu báo thù được Vương Lâm xác định sau khi nghe chuyện Tư Đồ Nam bị hại.","trangThai":"đối địch với Tư Đồ Nam và Vương Lâm","tabs":{"tienTrinh":[{"chuong":"@c0935","loai":"khai chiến","importance":"normal","giaiDoan":"Thù hận với Tư Đồ Nam","text":"Nhóm nữ tu Phượng Loan tinh được nhắc là lực lượng khiến Tư Đồ Nam trúng Dục Tiên Dục Tử, làm Vương Lâm quyết báo thù.","anchor":"Cừu này tất phải báo, chỉ có điều so với báo thù thì làm thế nào có thể giải độc trong người ngươi mới là quan trọng!"}]},"capNhatToi":"@c0935","nguon":["@c0935"]},{"id":"con-hu","name":"Côn Hư","cn":"","type":"tong-mon","typeLabel":"Thế lực tu chân","diaBan":"khong-ro","nhanVatChinh":["Tịch Huyên"],"blurb":"Thế lực được nhắc qua nghi vấn thân phận của thiếu nữ áo phấn. Lăng Thiên Hậu từng nghi nàng là Thánh nữ Côn Hư.","detail":"Côn Hư chưa trực tiếp xuất hiện trong chương, nhưng được nhắc như lai lịch nghi vấn của Tịch Huyên. Điều này khiến nhóm mây tía tại Triều tịch mang thêm màu sắc thế lực riêng.","capNhatToi":"@c0936","tabs":{"tienTrinh":[]},"nguon":["@c0936"]},{"id":"hoa-yeu-linh-quan","name":"Hỏa Yêu Linh quân","cn":"","type":"quan-doi","typeLabel":"Quân lực","diaBan":"Đô thành Hỏa Yêu, quận Hỏa Yêu trong vùng đất Yêu Linh","nhanVatChinh":["Mộc Vận","Hạt Kim","Người con gái mặc áo giáp xanh"],"blurb":"Chính thống cuối cùng còn giữ đô thành Hỏa Yêu sau khi quận Hỏa Yêu bị chiến tranh tàn phá. Lực lượng này bị đại quân bộ lạc Luyện Hồn vây ép và cuối cùng đầu hàng.","detail":"Hỏa Yêu Linh quân là lực lượng đại diện chính thống cuối cùng của quận Hỏa Yêu, do hai Yêu Soái và tám Yêu Tướng thống lĩnh giữ đô thành. Khi bộ lạc Luyện Hồn bao vây, Âu Dương Hoa ép Yêu Soái Mộc Vận và Hạt Kim đầu hàng; Hạt Kim lao ra định hủy tượng đá Lão tổ nhưng bị Thập Tam giết, sau đó người con gái mặc áo giáp xanh trên tường thành chấp nhận quy phục.","nguon":["@c0938"]},{"id":"truong-lao-doan-lien-minh","name":"Trưởng lão đoàn Liên minh","cn":"","type":"to-chuc","typeLabel":"Tổ chức","diaBan":"Liên minh","nhanVatChinh":["Hư Không Tử"],"blurb":"Tổ chức cao tầng của Liên minh, được nhắc khi phân biệt thân phận của Tôn Thiện. Tôn Thiện tuy là trưởng lão nhưng không thuộc trưởng lão đoàn này.","detail":"Trưởng lão đoàn Liên minh là tầng tổ chức được nhắc trong bối cảnh Hư Không Tử xuất hiện trước hố đen Đông Hải Triều Tịch. Chương cho biết Tôn Thiện mặc dù là trưởng lão nhưng không phải thành viên trưởng lão đoàn Liên minh, qua đó làm nổi bật vị thế Đại trưởng lão của Hư Không Tử trong hệ thống cao tầng Liên minh.","nguon":["@c0938","@c0986"],"tabs":{"tienTrinh":[{"chuong":"@c0986","loai":"nhắc tới","importance":"normal","giaiDoan":"Tiêu chuẩn thành viên","text":"Trưởng lão đoàn Liên Minh được nhắc là nơi lấy pháp bảo Thứ Không Niết làm một tiêu chuẩn thành viên.","anchor":"Một trong những tiêu chuẩn của trưởng lão đoàn Liên Minh chính là phải có một pháp bảo cấp THứ Không Niết"}]},"trangThai":"đang tồn tại"},{"id":"quan-hoa-yeu-faction","name":"Quận Hỏa Yêu","cn":"","type":"the-luc-cu","typeLabel":"Thế lực cũ","diaBan":"Quận Hỏa Yêu, vùng đất Yêu Linh","nhanVatChinh":["Mộc Vận","Hạt Kim","Người con gái mặc áo giáp xanh"],"blurb":"Một thế lực cũ trong vùng đất Yêu Linh, bị chiến tranh và cuộc tấn công của bộ lạc Luyện Hồn làm sụp đổ. Sau khi đô thành đầu hàng, quận này hoàn toàn trở thành đô thành của bộ lạc Luyện Hồn.","detail":"Quận Hỏa Yêu sau chiến tranh phủ đầy xác chết, các thế lực nhỏ hoặc đầu hàng hoặc bị tiêu diệt. Phần chính thống cuối cùng là Hỏa Yêu Linh quân giữ đô thành Hỏa Yêu, nhưng trước sức ép của đại quân Luyện Hồn, lệnh Hồn diệt và cái chết của Hạt Kim, đô thành chấp nhận đầu hàng; từ đó quận Hỏa Yêu bị bộ lạc Luyện Hồn tiếp quản hoàn toàn.","nguon":["@c0938"]},{"id":"phong-yeu-quan","name":"Phong Yêu Quận","cn":"","type":"dia-vuc-the-luc","typeLabel":"Địa vực / thế lực","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Diêu Tích Tuyết","Phong Yêu"],"blurb":"Một quận trong Yêu Linh chi địa, có Hoàng cung và hệ thống hầm ngầm tụ thi khí. Đây là nơi Diêu Tích Tuyết nhận truyền thừa Phong Yêu để đổi lấy lực lượng báo thù Vương Lâm.","detail":"Phong Yêu Quận là địa vực có Hoàng cung và hầm ngầm dưới Hoàng thành, nơi tồn tại hang động đầy thi khí cùng hệ thống động như tổ ong. Trong chương này, Diêu Tích Tuyết ở tại nơi truyền thừa dưới lòng đất, thân thể bị thi khí tàn phá và chấp nhận trả giá bằng thần thức, linh hồn để nhận lực lượng Phong Yêu nhằm báo thù Vương Lâm.","nguon":["@c0939"]},{"id":"yeu-linh-cuu-quan","name":"Yêu Linh Cửu Quận","cn":"","type":"cau-truc-the-luc","typeLabel":"Cấu trúc thế lực","diaBan":"Yêu Linh chi địa","nhanVatChinh":[],"blurb":"Hệ thống chín quận trong Yêu Linh chi địa, được giải thích gắn với chín phần Cổ Yêu và cơ chế các Yêu Linh hấp thu yêu khí để chữa thương, mưu cầu hợp nhất.","detail":"Trong suy luận của Vương Lâm về Cổ Yêu và Cửu Yêu, Yêu Linh Cửu Quận là cấu trúc gồm chín quận của Yêu Linh chi địa. Mỗi quận liên hệ tới một phần Cổ Yêu, nơi các Yêu Linh dựa vào yêu khí để khôi phục và hướng tới trạng thái Cửu Linh quy nhất.","nguon":["@c0941"]},{"id":"van-yeu-quan","name":"Vân Yêu Quận","cn":"","type":"quan","typeLabel":"Quận","diaBan":"Yêu Linh chi địa","nhanVatChinh":[],"blurb":"Một quận trong Yêu Linh chi địa, được nhắc qua ký ức tia Yêu Thức Vân Yêu như nơi đã tan tành sau biến cố.","detail":"Vân Yêu Quận xuất hiện trong phần ký ức của tia Yêu Thức Vân Yêu còn sót lại trong tượng đá. Sau khi nơi này tan tành, Yêu Tháp không thể tiếp tục lưu lại, khiến tia Yêu Thức trôi dạt rồi nhập vào tượng đá của Luyện Hồn bộ lạc.","nguon":["@c0941"]},{"id":"truyen-nhan-pha-diet-cam","name":"Truyền nhân Phá Diệt Cấm","cn":"","type":"truyen-thua","typeLabel":"Truyền thừa","diaBan":"không rõ","nhanVatChinh":["Vương Lâm"],"blurb":"Nhóm người thừa kế Phá Diệt Cấm, được nhắc qua yêu cầu sở hữu Tâm Cấm la bàn.","detail":"Tâm Cấm la bàn được nêu là vật bất cứ truyền nhân nào của Phá Diệt Cấm cũng cần phải có. Trong chương này, Vương Lâm dùng vật đó để phá thủy khí cấm của Tiên phủ, cho thấy truyền thừa này gắn với năng lực lấy cấm phá cấm.","trangThai":"được nhắc qua pháp bảo truyền thừa","capNhatToi":"@c0943","nguon":["@c0943"]},{"id":"yeu-linh-tien-phu","name":"Yêu Linh Tiên phủ","cn":"","type":"dia-diem-the-luc","typeLabel":"Động phủ liên quan","diaBan":"Yêu Linh chi địa","nhanVatChinh":["Vương Lâm","Cổ Yêu Bối La"],"blurb":"Mục tiêu mà Vương Lâm quyết phải tiến vào sau khi vượt qua động phủ đang bị nữ tử áo trắng trấn giữ.","detail":"Trong lúc bị nữ tử áo trắng áp chế, Vương Lâm vẫn xác định bản thân nhất định phải vào Yêu Linh Tiên phủ. Nếu đánh cược thất bại, hắn dự tính chạy đi tìm Cổ Yêu Bối La phá nát nơi này để mở đường.","trangThai":"được Vương Lâm nhắm tới","capNhatToi":"@c0947","nguon":["@c0947"]},{"id":"tien-de-bat-phi","name":"Tiên đế bát phi","cn":"","type":"nhom-danh-vi","typeLabel":"Nhóm danh vị","diaBan":"Tiên phủ Thanh Lâm","nhanVatChinh":["Hoa Phi Hàm Yên","Thanh Lâm"],"blurb":"Nhóm tám phi gắn với Tiên Đế Thanh Lâm, được hé lộ qua thân phận của Hoa Phi Hàm Yên.","detail":"Hoa Phi Hàm Yên tự xưng là một trong tiên đế bát phi, qua đó cho thấy quanh Thanh Lâm từng có nhóm phi tử hoặc danh vị thân cận trong tiên phủ.","thanhVien":[{"ten":"Hoa Phi Hàm Yên","chucVu":"một trong tiên đế bát phi","tuChuong":"@c0949","trangThai":"đã chết, còn hoa tiên tồn tại trong động phủ"}],"capNhatToi":"@c0949","nguon":["@c0949"]},{"id":"ngu-hanh-thuy-tan-ma","name":"Ngũ Hành Thủy Tán Ma","cn":"","type":"khac","typeLabel":"Danh xưng hoặc hệ Tán Ma","diaBan":"tháp đen trong hoang mạc cát đen @c0957","nhanVatChinh":["Minh Hải"],"blurb":"Ngũ Hành Thủy Tán Ma là danh xưng gắn với Minh Hải khi hắn tự xưng Ma phó. Chương này chưa nói rõ đây là thế lực, hệ phái hay cấp bậc trong tháp đen.","detail":"Minh Hải xuất hiện trên đỉnh tháp đen và tự xưng là Ma phó Ngũ Hành Thủy Tán Ma. Thông tin hiện có chỉ xác nhận danh xưng này liên quan đến thân phận Minh Hải, chưa đủ để xác định cơ cấu tổ chức hay lãnh đạo.","dinhDanh":"goc","trangThai":"chưa rõ bản chất tổ chức @c0957","thanhVien":[{"ten":"Minh Hải","chucVu":"Ma phó","tuChuong":"@c0957","trangThai":"đang xuất hiện"}],"tabs":{"tienTrinh":[{"chuong":"@c0957","loai":"nhắc tới","importance":"bridge","giaiDoan":"Minh Hải tự xưng","text":"Minh Hải tự xưng là Ma phó Ngũ Hành Thủy Tán Ma khi xuất hiện trên đỉnh tháp đen.","anchor":"Minh Hải – Ma phó Ngũ Hành Thủy Tán Ma. Giết ta, ngươi có cơ hội đạt được Sơn Hà Đồ - Đại Mạc Cô Yên của Tiên Đế Thanh Lâm!"}]},"capNhatToi":"@c0957","nguon":["@c0957"]},{"id":"chu-tuoc-thanh-tong","name":"Chu Tước Thánh Tông","cn":"朱雀聖宗","type":"tong-mon","typeLabel":"Thánh tông","diaBan":"Chưa rõ","nhanVatChinh":["Vương Lâm","Sáu lão già Toái Niết Chu Tước Thánh tông","Người lửa khổng lồ do nguyên thần Chu Tước hợp thành","Chu Tước Thánh Hoàng","Sáu lão già Toái Niết"],"blurb":"Chu Tước Thánh Tông là thế lực mà Vương Lâm thuộc về với thân phận người trong danh sách Chu Tước (@c0961). Tính tới mốc mới nhất, tông môn đã điều động sáu lão già Toái Niết và đích thân Chu Tước Thánh Hoàng nỗ lực cứu Vương Lâm trước Cổ Ma Tháp Già (@c1007, @c1013).","detail":"Vương Lâm được xác nhận là người trong Chu Tước Thánh Tông và nằm trong danh sách Chu Tước khi dấu ấn Chu Tước thức tỉnh (@c0961). Việc thức tỉnh này gắn với tư cách kế thừa Chu Tước và được người áo đen nhìn nhận là có thể khiến Chu Tước Thánh Tông vì Vương Lâm mà quật khởi tới một tầng mức mới (@c0985). Để cứu Vương Lâm, sáu lão già của tông xuất trận nhưng bị Cổ Ma Tháp Già áp chế khiến ba người thổ huyết (@c1007); sau đó một trong các lão già Toái Niết tự bạo hy sinh, số còn lại cùng Hoa Phi và người lửa khổng lồ tiếp tục ứng chiến (@c1008). Chu Tước Thánh Hoàng đại diện tông đứng ra chủ trì việc hợp nhất tứ thánh khí, thi triển ba thức ấn quyết để tấn công Cổ Ma Tháp Già (@c1013).","thanhVien":[{"ten":"Vương Lâm","chucVu":"Chu Tước tử","tuChuong":"@c0961","trangThai":"liên hệ thân phận"},{"ten":"Sáu lão già Toái Niết Chu Tước Thánh tông","chucVu":"Lão già Toái Niết","tuChuong":"@c1007","trangThai":"đang giao chiến"},{"ten":"Người lửa khổng lồ do nguyên thần Chu Tước hợp thành","chucVu":"Chiến lực hỗ trợ","tuChuong":"@c1007","trangThai":"đang giao chiến"},{"ten":"Lão già Toái Niết tự bạo","chucVu":"Hộ vệ","tuChuong":"@c1008","trangThai":"tu-vong"},{"ten":"Hoa Phi","chucVu":"Chiến lực","tuChuong":"@c1008","trangThai":"dang-chien"}],"quanHe":"Gắn với Tứ Thánh Tông và danh sách Chu Tước.","trangThai":"được dự báo quật khởi","tabs":{"tienTrinh":[{"chuong":"@c0961","loai":"nhắc tới","importance":"normal","giaiDoan":"Danh sách Chu Tước","text":"Chương xác nhận Vương Lâm là người trong Chu Tước Thánh Tông và thuộc danh sách Chu Tước khi dấu ấn thức tỉnh.","anchor":"mà Vương Lâm lại là người trong Chu Tước Thánh Tông, thân là một người trong danh sách Chu Tước"},{"chuong":"@c0985","loai":"nhắc tới","importance":"normal","giaiDoan":"Dự báo quật khởi","text":"Người áo đen nhận định Chu Tước Thánh tông có thể vì Vương Lâm mà quật khởi tới mức mới trong Liên Minh Tinh Vực.","trangThaiMoc":"được dự báo quật khởi","anchor":"Chu Tướng Thánh tông sẽ bởi vì người nàu mà lại quật khởi"},{"chuong":"@c1007","loai":"khai chiến","importance":"normal","giaiDoan":"Bị Cổ Ma ghìm chân","text":"Sáu lão già Chu Tước Thánh tông muốn cứu Vương Lâm nhưng bị Cổ Ma Tháp Già áp chế, khiến ba người thổ huyết trọng thương và không kịp cứu viện.","anchor":"Sáu lão già Chu Tước Thánh tông ở xa xa cơ hồ đều rống giận"},{"chuong":"@c1008","loai":"khai-chien","importance":"major","trangThaiMoc":"Tổn thất nặng","giaiDoan":"Một lão tự bạo, năm lão chống Cổ Ma ở hạ phong","text":"Một trong sáu lão già Toái Niết tự bạo hy sinh cứu Vương Lâm. Năm lão còn lại cùng Hoa Phi và người lửa khổng lồ dùng pháp bảo cấp Không chống Cổ Ma Tháp Già nhưng bị thần thông Cổ Ma biến ảo ép vào tuyệt đối hạ phong.","anchor":"diệt đi hy vọng của Chu Tước Thánh tông bọn họ"},{"chuong":"@c1013","loai":"xuất hiện","importance":"major","giaiDoan":"Chủ trì hợp nhất tứ thánh khí","trangThaiMoc":"hoat-dong","text":"Chu Tước Thánh Hoàng đại diện tông chủ trì hợp nhất tứ thánh khí, thi triển ba thức ấn quyết tấn công Cổ Ma Tháp Già.","anchor":"Thái Cổ thánh khí của Chu Tước Thánh Tông ta thực tế chỉ có ba thức ấn quyết"}]},"capNhatToi":"@c0961","nguon":["@c0961","@c0985","@c1007","@c1008","@c1013"],"uyLuc":"Chu Tước Thánh Hoàng hợp nhất tứ thánh khí, thi triển ba thức ấn quyết tấn công Cổ Ma Tháp Già (@c1013).","dacDiem":"Thế lực gắn với danh sách Chu Tước và tư cách kế thừa Chu Tước, đứng đầu là Chu Tước Thánh Hoàng, có nhóm lão già Toái Niết dưới trướng.","congNang":["Nắm giữ danh sách Chu Tước và dấu ấn Chu Tước có thể thức tỉnh nơi người kế thừa (@c0961)","Có các lão già cảnh giới Toái Niết, có thể tự bạo hy sinh trong chiến đấu (@c1007, @c1008)","Chu Tước Thánh Hoàng chủ trì hợp nhất tứ thánh khí và thi triển ba thức ấn quyết để tấn công (@c1013)"]},{"id":"con-hu-tinh-vuc","name":"Côn Hư Tinh Vực","cn":"","type":"tinh-vuc","typeLabel":"Tinh vực","diaBan":"Côn Hư Tinh Vực","nhanVatChinh":["Côn Hư Thánh Nữ"],"blurb":"Tinh vực từng là mục tiêu tranh đoạt dữ dội giữa Tu Chân Liên Minh và Tứ Thánh Tông.","detail":"Côn Hư Tinh Vực được nhắc trong hồi tưởng của Hư Không Tử như nơi Tu Chân Liên Minh từng cùng Tứ Thánh Tông tranh đoạt. Côn Hư Thánh Nữ hiện đi cùng phe Hư Không Tử, thể hiện liên hệ của tinh vực này với tuyến đối kháng giữa Liên Minh và Tứ Thánh Tông.","nguon":["@c0962"]},{"id":"huyen-vu-thanh-tong","name":"Huyền Vũ Thánh Tông","cn":"玄武聖宗","type":"tong-mon","typeLabel":"Thánh tông","diaBan":"","nhanVatChinh":[],"blurb":"Huyền Vũ Thánh Tông là một trong bốn mạch của Tứ Thánh Tông, được nêu là không thiếu người thức tỉnh. Tính tới mốc mới nhất, chỉ có ba lão già tới tham chiến và khí thế của mạch này bị đánh giá thấp hơn ba thánh thú còn lại, đồng thời nội bộ chia thành hai phái sau biến cố.","detail":"Huyền Vũ Thánh Tông là một trong bốn mạch của Tứ Thánh Tông. Theo nhận định của Hư Không Tử, mạch Huyền Vũ có nguy cơ thức tỉnh nhỏ hơn và không thiếu người thức tỉnh, nên không phải nhánh khiến hắn kiêng kị nhất trong biến cố Chu Tước thức tỉnh. Tới thời điểm tham chiến, mạch này chỉ cử ba lão già xuất trận và bị đánh giá là khí thế thấp hơn ba thánh thú kia; sau sự biến, nội bộ Huyền Vũ chia làm hai phái.","nguon":["@c0962","@c1008","@c1013"],"tabs":{"tienTrinh":[{"chuong":"@c1013","loai":"xuất hiện","importance":"major","giaiDoan":"Xuất hiện trong trạng thái suy yếu","trangThaiMoc":"suy","text":"Chỉ ba lão già tới tham chiến, Huyền Vũ hóa ra khí thế thấp hơn ba thánh thú kia. Nội bộ chia hai phái sau sự kiện thánh hoàng phản bội, bị Tu Chân Liên Minh tấn công.","anchor":"tông này sau khi trải qua sự kiện thánh hoàng phản bội, nội bộ chia thành hai phái"}]},"trangThai":"suy","dacDiem":"Nguy cơ thức tỉnh nhỏ hơn nhưng không thiếu người thức tỉnh; khi tham chiến chỉ cử ba lão già và khí thế bị đánh giá thấp hơn ba thánh thú còn lại; nội bộ chia làm hai phái sau sự biến @c1013"},{"id":"bach-ho-thanh-tong","name":"Bạch Hổ Thánh Tông","cn":"白虎聖宗","type":"tong-mon","typeLabel":"Thánh tông","diaBan":"","nhanVatChinh":[],"blurb":"Bạch Hổ Thánh Tông là một trong bốn mạch của Tứ Thánh Tông, người thức tỉnh thường mang khí thế hung ác và thiên về sát phạt. Đây là thế lực gắn với thuộc tính Bạch Hổ phương Tây trong bố cục Tứ Thánh.","detail":"Bạch Hổ Thánh Tông là một trong bốn mạch của Tứ Thánh Tông. Theo lời Hư Không Tử, người thức tỉnh của mạch này thường có dáng vẻ, khí thế độc ác, về sau trở thành kiểu tiên nhân giết chóc. Trong tiến trình, các cao thủ của tông môn hành động theo lối kết trận tập thể: bảy lão già Bạch Hổ Thánh Tông ngồi thành trận dung hợp bảy khối tàn kim để hóa thành Bạch Hổ phương Tây, đồng thời phối hợp cùng các mạch còn lại của Tứ Thánh (@c1013).","nguon":["@c0962","@c1008","@c1013"],"tabs":{"tienTrinh":[{"chuong":"@c1013","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","trangThaiMoc":"hoat-dong","text":"Bảy lão già Bạch Hổ Thánh Tông ngồi thành trận dung hợp bảy khối tàn kim hóa Bạch Hổ phương Tây, phối hợp tứ thánh khí hợp nhất.","anchor":"bảy lão già đến từ Bạch Hổ Thánh Tông đều khoanh chân ngồi xuống"}]},"dacDiem":"Người thức tỉnh của mạch thường mang dáng vẻ, khí thế độc ác, thiên về sát phạt; gắn với thuộc tính Bạch Hổ phương Tây.","congNang":["Bảy lão già kết trận dung hợp bảy khối tàn kim, hóa thành Bạch Hổ phương Tây @c1013","Phối hợp cùng các mạch khác của Tứ Thánh Tông trong bố trận @c1013"]},{"id":"tien-de-di-san","name":"Tiên Đế","cn":"","aliases":["Di sản Tiên Đế"],"type":"di-san","typeLabel":"Di sản và thuộc hạ cũ","diaBan":"Động phủ Tiên Đế","nhanVatChinh":["Tiên Đế","Tàn Đao"],"blurb":"Di sản Tiên Đế được nhắc qua động phủ, bình bạch ngọc và thân phận hộ vệ cũ của Tàn Đao. Chương này xác nhận Tàn Đao từng là một trong tứ đại hộ vệ của Tiên Đế.","detail":"Trong động phủ Tiên Đế, bình bạch ngọc bị phá khiến các tu sĩ thoát ra ngoài. Bối La nhận ra người giáp đen là Tàn Đao, xưa kia thuộc tứ đại hộ vệ của Tiên Đế, nay đã bị Cổ Ma luyện hóa thành Tán Ma.","thanhVien":[{"ten":"Tàn Đao","chucVu":"Tứ đại hộ vệ cũ","tuChuong":"@c0963","trangThai":"đã bị luyện hóa thành Tán Ma"}],"tabs":{"tienTrinh":[{"chuong":"@c0963","loai":"nhắc tới","importance":"normal","giaiDoan":"Hộ vệ cũ lộ thân","text":"Tàn Đao được Bối La xác nhận từng là một trong tứ đại hộ vệ của Tiên Đế, nhưng nay đã thành Tán Ma.","anchor":"Xưa kia là Tàn Đao, một trong tứ đại hộ vệ của Tiên Đế"}]},"capNhatToi":"@c0963","nguon":["@c0963"]},{"id":"tan-ma","name":"Tán Ma","cn":"","aliases":[],"type":"ma-dao","typeLabel":"Loại tồn tại ma đạo","diaBan":"Động phủ Tiên Đế","nhanVatChinh":["Tàn Đao","Cổ Ma"],"blurb":"Tán Ma là trạng thái hoặc loại tồn tại ma đạo được nhắc qua Tàn Đao. Chương này cho biết Tàn Đao hiện là một trong Tán Ma do Cổ Ma luyện hóa.","detail":"Tàn Đao xưa là hộ vệ của Tiên Đế, nhưng nay đã bị Cổ Ma luyện hóa thành Tán Ma. Cuối chương, hắn chuẩn bị ra tay bằng ma khí phát ra từ áo giáp đen.","nguonGoc":"Do Cổ Ma luyện hóa","thanhVien":[{"ten":"Tàn Đao","chucVu":"Một trong Tán Ma","tuChuong":"@c0963","trangThai":"đang hoạt động"}],"tabs":{"tienTrinh":[{"chuong":"@c0963","loai":"nhắc tới","importance":"normal","giaiDoan":"Tàn Đao thành Tán Ma","text":"Bối La nói rõ Tàn Đao hiện đã trở thành một trong Tán Ma do Cổ Ma luyện hóa.","anchor":"hôm nay lại trở thành một trong Tán Ma do Cổ Ma luyện hóa"}]},"capNhatToi":"@c0963","nguon":["@c0963"]},{"id":"phu-toc","name":"Phù Tộc","cn":"","type":"toc-quan","typeLabel":"Tộc quần","diaBan":"Không rõ","nhanVatChinh":["Thu Dao"],"blurb":"Phù Tộc là tộc sở hữu thánh khí được Tán Ma mượn để vùi lấp Tiên Trì. Thánh khí này gắn với bẫy dưới nơi chôn Thanh Lâm.","detail":"Trong lời Tán Ma, thánh khí của Phù Tộc là công cụ được dùng để vùi lấp Tiên Trì, khiến nơi này trở thành bẫy hiến tế cho Cổ Ma.","dacDiem":"Sở hữu thánh khí dùng để vùi lấp Tiên Trì.","tranPhai":["Thánh khí của Phù Tộc"],"tabs":{"tienTrinh":[{"chuong":"@c0964","loai":"nhắc tới","importance":"normal","giaiDoan":"Thánh khí bị mượn","text":"Tán Ma nhắc đến thánh khí của Phù Tộc như vật được hắn mượn để vùi lấp Tiên Trì.","anchor":"mượn thánh khí của Phù Tộc, vùi lấp Tiên Trì"}]},"capNhatToi":"@c0964","nguon":["@c0964"]},{"id":"hoi-dong-truong-lao-cua-tu-chan-lien-minh","name":"Hội đồng trưởng lão của Tu Chân Liên Minh","cn":"","type":"to-chuc-noi-bo","typeLabel":"Tổ chức nội bộ","diaBan":"Tu Chân Liên Minh","nhanVatChinh":["Thiên Vận Tử áo xám"],"blurb":"Tầng quyền lực nội bộ của Tu Chân Liên Minh, được nhắc qua hồi ức của Hư Không Tử về Thiên Vận Tử áo xám.","detail":"Hư Không Tử nhớ rằng Thiên Vận Tử áo xám năm xưa từng một mình vào Tu Chân Liên Minh, đánh bại nhiều tu sĩ đại thần thông. Ngay cả một vài người trong hội đồng trưởng lão cũng không phải đối thủ của hắn; hắn giết một thành viên hội đồng trưởng lão rồi trở thành thành viên mới.","quanHe":"Trực thuộc Tu Chân Liên Minh","thanhVien":[{"ten":"Thiên Vận Tử áo xám","chucVu":"Thành viên mới","tuChuong":"@c0965","trangThai":"được nhắc trong hồi ức"}],"tabs":{"tienTrinh":[{"chuong":"@c0965","loai":"nhắc tới","importance":"normal","giaiDoan":"Uy danh áo xám","text":"Hội đồng trưởng lão được nhắc là tầng quyền lực từng có thành viên bị Thiên Vận Tử áo xám giết, sau đó hắn trở thành thành viên mới.","anchor":"thậm chí người của hội đồng trưởng lão cũng có một vài người không phải là đối thủ của người này"}]},"dinhDanh":"goc","capNhatToi":"@c0965","nguon":["@c0965"]},{"id":"phu-gioi","name":"Phù Giới","cn":"","type":"gioi-vuc","typeLabel":"Giới vực của Phù Tộc","diaBan":"Phù Giới","nhanVatChinh":["Thu Dao"],"blurb":"Phù Giới là giới vực của Phù Tộc được Thu Dao nhắc khi oán trách Thanh Lâm.","detail":"Theo lời Thu Dao, Thanh Lâm từng hứa để Tiên Giới cùng Phù Giới cùng tồn tại, nhưng ký ức Tháp Sơn lại cho thấy nhiều đời tộc nhân Phù Tộc bị nô ấn.","nguonGoc":"giới vực của Phù Tộc","quanHe":"Được đặt đối ứng với Tiên Giới trong lời Thu Dao.","trangThai":"được nhắc lại @c0966","tabs":{"tienTrinh":[{"chuong":"@c0966","loai":"nhắc tới","importance":"normal","giaiDoan":"Thu Dao nhắc Phù Giới trong lời oán trách Thanh Lâm.","text":"Thu Dao nói Thanh Lâm từng hứa để Tiên Giới và Phù Giới cùng tồn tại.","anchor":"Tiên Giới của cùng với Phù Giới của ta cùng tồn tại"}]},"capNhatToi":"@c0966","nguon":["@c0966"]},{"id":"phong-gioi-faction","name":"Phong Giới","cn":"","type":"gioi-vuc","typeLabel":"Giới vực","diaBan":"Phong Giới","nhanVatChinh":["Thanh Lâm","Vương Lâm"],"blurb":"Phong Giới được Thanh Lâm gọi là nơi ông muốn bảo vệ trước âm mưu của Thu Dao, Chưởng Tôn và thế giới bên ngoài. Đây là đối tượng bị nhắm tới trong mạch xung đột vượt khỏi động phủ Tiên Đế.","detail":"Theo lời Thanh Lâm, mục đích thật của Thu Dao khi tới Phong Giới không phải như lời nàng từng nói mà là hủy diệt sức mạnh nơi này. Ông cũng muốn hậu nhân Phong Giới ghi nhớ sát khí của những kẻ đến từ bên ngoài.","dinhDanh":"goc","quanHe":"Đối lập với thế giới bên ngoài trong lời Thanh Lâm.","trangThai":"bị thế giới bên ngoài nhắm tới","tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"nhắc tới","importance":"normal","giaiDoan":"Hồi ức Thanh Lâm","text":"Thanh Lâm nói Thu Dao tới Phong Giới với mục đích hủy diệt sức mạnh nơi này, đồng thời nhắc trách nhiệm bảo vệ hậu nhân Phong Giới.","anchor":"Mục đích ngươi tới Phong Giới của ta hoàn toàn không phải"}]},"capNhatToi":"@c0970","nguon":["@c0970"]},{"id":"the-gioi-ben-ngoai","name":"Thế giới bên ngoài","cn":"","type":"ngoai-vuc","typeLabel":"Ngoại vực","diaBan":"bên ngoài Phong Giới","nhanVatChinh":["Chưởng Tôn","Thu Dao","Thánh tổ Phù Tộc"],"blurb":"Thế giới bên ngoài là nơi Phù Tộc và Chưởng Tôn được Thanh Lâm nhắc tới. Trong lời ông, đây là nguồn uy hiếp ngoại lai đối với Tiên Giới và Phong Giới.","detail":"Thanh Lâm nói Phù Tộc từ thế giới bên ngoài tiến vào Tiên Giới, còn thân phận thật của Thu Dao ở nơi đó là con gái Chưởng Tôn. Ông muốn hậu nhân Phong Giới không quên sát khí của những kẻ đến từ bên ngoài.","dinhDanh":"goc","quanHe":"Đối lập với Phong Giới và Tiên Giới trong lời Thanh Lâm.","trangThai":"nguồn uy hiếp ngoại lai","tabs":{"tienTrinh":[{"chuong":"@c0970","loai":"nhắc tới","importance":"normal","giaiDoan":"Hồi ức Thanh Lâm","text":"Thế giới bên ngoài được nhắc như nơi Phù Tộc tiến vào Tiên Giới và là nguồn sát khí mà Thanh Lâm muốn hậu nhân Phong Giới ghi nhớ.","anchor":"vĩnh viễn không thể quên sát khí nồng đậm của những kẻ đến từ bên ngoài"}]},"capNhatToi":"@c0970","nguon":["@c0970"]},{"id":"doan-tu-si-ao-do-theo-chu-tuoc-chan-linh","name":"Đoàn tu sĩ áo đỏ theo Chu Tước Chân Linh","cn":"","type":"doan-tu-si","typeLabel":"Đoàn tu sĩ","diaBan":"Giữa Tinh Không trong Liên Minh Tinh Vực","nhanVatChinh":["Chu Tước Chân Linh","Sáu lão già đi trước đoàn tu sĩ áo đỏ"],"blurb":"Đoàn hơn một ngàn tu sĩ nam nữ mặc áo đỏ thẫm đi theo Chu Tước Chân Linh giữa Tinh Không.","detail":"Đoàn tu sĩ này xuất hiện sau Chu Tước Chân Linh, số lượng không dưới một ngàn người, đều mặc áo đỏ thẫm. Phía trước đoàn còn có sáu lão già tản ra khí tức tu vi kinh người; khi Chu Tước Chân Linh đột nhiên phát tiếng kêu vì cảm ứng tâm thần Vương Lâm lướt qua, những người trong đoàn đều kinh ngạc.","nguon":["@c0977"]},{"id":"con-lon-hu-canh","name":"Côn Lôn hư cảnh","cn":"","type":"the-luc","typeLabel":"Thế lực truyền thừa","diaBan":"","nhanVatChinh":["Thôn cô xinh đẹp"],"blurb":"Nơi thôn cô xinh đẹp từng nghe trưởng bối bàn luận về cấp bậc bảo vật cao tầng.","detail":"Ký ức từ Côn Lôn hư cảnh giúp thôn cô xinh đẹp liên hệ thanh kiếm thép của Vương Lâm với hệ thống bảo vật Bảo, Linh, Huyền, Tiên, Không, Niết.","thanhVien":[{"ten":"Thôn cô xinh đẹp","chucVu":"người thuộc Côn Lôn hư cảnh","tuChuong":"@c0985","trangThai":"đang liên hệ"}],"tabs":{"tienTrinh":[{"chuong":"@c0985","loai":"nhắc tới","importance":"normal","giaiDoan":"Tri thức bảo vật","text":"Côn Lôn hư cảnh được nhắc qua ký ức của thôn cô xinh đẹp về lời trưởng bối bàn luận cấp bậc bảo vật.","anchor":"Trong trí nhớ của nàng ở trong Côn Lôn hư cảnh"}]},"capNhatToi":"@c0985","nguon":["@c0985"]},{"id":"vu-chi-kiem-tien-vu-chi-kiem-linh","name":"Vũ chi Kiếm tiên / Vũ chi Kiếm linh","cn":"","type":"he-tien-gioi","typeLabel":"Hệ Tiên giới","diaBan":"Vũ chi Tiên giới","nhanVatChinh":["Chu Dật"],"blurb":"Vũ chi Kiếm tiên và Vũ chi Kiếm linh là thân phận Chu Dật dùng để chứng thực quan hệ với Thanh Sương. Vương Nguy, Hồ Quyên dựa vào thân phận này cùng lời kể của Chu Dật để tin chuyện năm xưa.","detail":"Chu Dật dùng thân phận Vũ chi Kiếm tiên khi nói về Thanh Sương, sau đó thân phận Vũ chi Kiếm linh của hắn được xem là chứng cứ quan trọng cho lời kể về mối nhân duyên với Tiên Quân Thanh Sương. Thực thể này gắn với Vũ chi Tiên giới và thân phận hiện tại của Chu Dật.","thanhVien":[{"ten":"Chu Dật","chucVu":"Vũ chi Kiếm linh","tuChuong":"@c0988","trangThai":"đang gắn bó"}],"tabs":{"tienTrinh":[{"chuong":"@c0988","loai":"nhắc tới","importance":"normal","giaiDoan":"Thân phận được dùng làm chứng cứ","text":"Thân phận Vũ chi Kiếm linh của Chu Dật được Vương Nguy và Hồ Quyên xem là căn cứ để tin lời kể về Thanh Sương.","anchor":"thân phận Vũ chi Kiếm linh của Chu Dật"}]},"capNhatToi":"@c0988","nguon":["@c0988"]},{"id":"tu-thanh-tong-thanh-long","name":"Tứ Thánh Tông Thanh Long","cn":"","type":"tong-mon","typeLabel":"Nhánh thế lực","diaBan":"không rõ","nhanVatChinh":["Tứ Thánh Tông Thanh Long"],"blurb":"Nhánh Thanh Long của Tứ Thánh Tông được nhắc trong lời Bối La về biến cố tranh đoạt truyền thừa Tiên giới.","detail":"Sau đại kiếp Tiên giới, Tứ Thánh Tông Thanh Long từng cùng Trọng Huyền Tử và nhiều luyện khí sĩ nổi danh tham dự tranh đoạt trong Tiên giới. Chương này chỉ hé lộ vai trò của phe này qua lời kể của Bối La.","quanHe":["Từng cùng Trọng Huyền Tử tranh đoạt truyền thừa Tiên giới @c0990"],"tabs":{"tienTrinh":[{"chuong":"@c0990","loai":"nhắc tới","importance":"bridge","giaiDoan":"Tranh đoạt truyền thừa Tiên giới","text":"Tứ Thánh Tông Thanh Long được nhắc là một phe từng cùng Trọng Huyền Tử tranh đoạt trong Tiên giới sau đại kiếp.","anchor":"cùng cướp đoạt với rât Tứ Thánh Tông Thanh Long"}]},"capNhatToi":"@c0990","nguon":["@c0990"]},{"id":"co-ma-mach","name":"Cổ Ma / mạch Cổ Ma","cn":"","aliases":["Cổ Ma","mạch Cổ Ma"],"type":"chung-mach","typeLabel":"Chủng mạch / thế lực","diaBan":"liên quan tầng chín Tiên phủ trong chương này","nhanVatChinh":["Cổ Ma Tháp Già"],"blurb":"Cổ Ma / mạch Cổ Ma được đặt trong nghi vấn của Vương Lâm về quan hệ giữa Cổ Ma, Cổ Yêu, Thiên Vận Tử và Lăng Thiên Hầu. Tại tầng chín, Tháp Già tự xưng bản ma và đang tiến hành đoạt xá.","detail":"Trong chương này, Cổ Ma xuất hiện như một mạch thế lực gắn với Tháp Già, ma ảnh, ma lực và biến cố đoạt xá ở tầng chín Tiên phủ. Vương Lâm cũng đặt Cổ Ma vào chuỗi nghi vấn liên hệ với Cổ Yêu, Thiên Vận Tử và Lăng Thiên Hầu.","trangThai":"đang hiện diện qua Tháp Già và ma ảnh","thanhVien":[{"ten":"Cổ Ma Tháp Già","chucVu":"Cổ Ma","tuChuong":"@c0995","trangThai":"đang đoạt xá"}],"tabs":{"tienTrinh":[{"chuong":"@c0995","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ mối liên hệ quỷ dị","text":"Vương Lâm đặt Cổ Ma cùng Cổ Yêu, Thiên Vận Tử và Lăng Thiên Hầu vào một nghi vấn liên hệ quỷ dị, trong khi Tháp Già đang dùng ma ảnh và ma lực tại tầng chín.","anchor":"Cổ Ma, Cổ Yêu, Thiên Vận Tử, Lăng Thiên Hầu, giữa bọn họ nhất định có một mối liên hệ quỷ dị nào đó"}]},"capNhatToi":"@c0995","nguon":["@c0995"]},{"id":"con-hu-chi-canh","name":"Côn Hư Chi Cảnh","cn":"","type":"dia-vuc-the-luc","typeLabel":"Địa vực / thế lực","diaBan":"Côn Hư Chi Cảnh","nhanVatChinh":["Lão nhân Côn Hư","Côn Hư Thánh Nữ Mộc Băng Mi"],"blurb":"Côn Hư Chi Cảnh là nơi lão nhân Côn Hư và Côn Hư Thánh Nữ Mộc Băng Mi cảm ứng biến cố từ Yêu Linh chi địa.","detail":"Trong lúc thân thể Thanh Sương bị Cổ Ma chi phối làm chấn động Liên Minh Tinh Vực, Côn Hư Chi Cảnh cũng có phản ứng. Lão nhân Côn Hư ở đây nhìn về Yêu Linh chi địa, nhận ra có người tỉnh lại nhưng đồng thời phủ định đó không phải người hắn nghĩ đến; Mộc Băng Mi đứng bên cạnh cũng chứng kiến phản ứng này.","nguon":["@c0996"]},{"id":"co-chi-nhat-toc","name":"Cổ chi nhất tộc","cn":"","type":"chung-toc","typeLabel":"Chủng tộc cổ","diaBan":"không rõ","nhanVatChinh":["Cổ Ma Tháp Già","Bối La"],"blurb":"Nguồn gốc cổ xưa được Tháp Già nhắc tới khi đối thoại với Bối La.","detail":"Tháp Già nói tổ tiên của hắn và Bối La năm xưa đều thuộc cổ chi nhất tộc, làm nền cho ân oán giữa Cổ Ma và Cổ Yêu về thân thể Thanh Sương và trí nhớ.","nguon":["@c0997"]},{"id":"mach-chuong-ton-la-khuong","name":"Mạch chưởng tôn La Khuông","cn":"","type":"su-mon","typeLabel":"Quan hệ sư môn","diaBan":"không rõ","nhanVatChinh":["La Khuông","Người áo đen"],"blurb":"Mạch chưởng tôn La Khuông được hé lộ qua lời tự xưng của Người áo đen. Người áo đen gọi mình là đệ tử thứ bảy của chưởng tôn La Khuông.","detail":"Trong lúc nguyên thần sắp bị đao mang Cổ Ma xuyên thấu, Người áo đen truyền thần niệm nêu thân phận là đệ tử thứ bảy của chưởng tôn La Khuông. Danh xưng này khiến đao mang dừng lại rồi bỏ qua hắn, cho thấy mạch này có trọng lượng đặc biệt đối với Cổ Ma Tháp Già.","lanhDaoHienThoi":"La Khuông","thanhVien":[{"ten":"Người áo đen","chucVu":"đệ tử thứ bảy theo lời tự xưng","tuChuong":"@c0998","trangThai":"đang sống"}],"quanHe":"Có liên hệ khiến Cổ Ma Tháp Già kiêng kỵ hoặc nhận biết qua danh xưng La Khuông.","trangThai":"được hé lộ","capNhatToi":"@c0998","tabs":{"tienTrinh":[{"chuong":"@c0998","loai":"nhắc tới","importance":"normal","giaiDoan":"Người áo đen nêu thân phận","text":"Người áo đen tự xưng là đệ tử thứ bảy của chưởng tôn La Khuông và nhờ đó khiến đao mang Cổ Ma bỏ qua nguyên thần.","anchor":"ta là đệ tử thứ bảy của chưởng tôn La Khuông"}]},"nguon":["@c0998"]},{"id":"co-chi-tam-toc","name":"Cổ chi tam tộc","cn":"","type":"toc-he","typeLabel":"Tộc hệ","diaBan":"Động phủ Thanh Sương","nhanVatChinh":["Vương Lâm","Cổ Yêu Bối La","Cổ Ma Tháp Già"],"blurb":"Ba nhánh Cổ Thần, Cổ Yêu và Cổ Ma cùng xuất hiện trong động phủ Thanh Sương, biến trận chiến tại tầng tám thành va chạm của cổ chi tam tộc.","detail":"Trong chương này, Vương Lâm hóa chân thân Cổ Thần, Bối La hiện thân thất tinh Cổ Yêu, còn Tháp Già lấy thân Cổ Ma đối đầu. Sự đồng thời xuất hiện của ba nhánh khiến chiến trường vượt khỏi phạm trù giao đấu tu sĩ thông thường, kéo theo va chạm giữa thần thông, huyết mạch và lực lượng cổ tộc trong động phủ Thanh Sương.","nguon":["@c0999"]},{"id":"chu-tuoc-chan-linh-faction","name":"Chu Tước Chân Linh","cn":"","type":"nhom-tu-si","typeLabel":"Nhóm tu sĩ","diaBan":"bên ngoài tinh không vùng đất Yêu Linh @c1001","nhanVatChinh":["Chu Tước Chân Linh"],"blurb":"Nhóm tu sĩ xuất hiện cùng Chu Tước Thánh Tông bên ngoài tinh không vùng đất Yêu Linh. Họ tham gia công kích phong ấn cho tới khi phong ấn tan vỡ.","detail":"Chu Tước Chân Linh cùng tu sĩ Chu Tước Thánh Tông liên tục đánh vào phong ấn vùng đất Yêu Linh từ bên ngoài tinh không. Hành động này góp phần làm phong ấn nổ vỡ và mở đường cho lực lượng Chu Tước tiến đến.","trangThai":"đang tham chiến","quanHe":"Cùng Chu Tước Thánh Tông công phá phong ấn vùng đất Yêu Linh","thanhVien":[{"ten":"Chu Tước Chân Linh","chucVu":"chân linh","tuChuong":"@c1001","trangThai":"tham gia công phá phong ấn"}],"tabs":{"tienTrinh":[{"chuong":"@c1001","loai":"khai chiến","importance":"normal","giaiDoan":"Phá phong ấn","text":"Chu Tước Chân Linh cùng Chu Tước Thánh Tông liên tục công kích phong ấn vùng đất Yêu Linh từ bên ngoài tinh không.","anchor":"những tu sĩ Chu Tước Chân Linh và Chu Tước Thánh Tông đang liên tục đánh vào"}]},"capNhatToi":"@c1001","nguon":["@c1001"]},{"id":"nhom-gan-tram-nguoi-di-sau-chu-tuoc","name":"Nhóm gần trăm người đi sau Chu Tước","cn":"","type":"nhom","typeLabel":"Nhóm chưa rõ danh xưng","diaBan":"Vùng đất Yêu Linh","nhanVatChinh":["Sáu người tóc trắng đi đầu sau Chu Tước"],"blurb":"Nhóm gần trăm người đi sau Chu Tước xuất hiện trên bầu trời sau khi Chu Tước chân linh tới. Sáu người đứng đầu đều tóc trắng, uy áp lớn lao và tu vi đủ long trời lở đất.","detail":"Sau khi Chu Tước chân linh giáng xuống và dung hợp vào Vương Lâm, trên bầu trời lại có gần trăm người xuất hiện. Chương chỉ nêu sáu người đứng đầu có tóc trắng, uy áp lớn lao và tu vi rất mạnh, chưa nói rõ danh xưng hay lai lịch thế lực.","quyMo":"gần trăm người","caoThuManhNhat":"sáu người tóc trắng đứng đầu","soCaoThu":"sáu người đứng đầu có uy áp lớn lao","trangThai":"vừa hiện thân","thanhVien":[{"ten":"Sáu người tóc trắng đi đầu sau Chu Tước","chucVu":"sáu người đứng đầu","tuChuong":"@c1005","trangThai":"đang hiện diện"}],"tabs":{"tienTrinh":[{"chuong":"@c1005","loai":"nhắc tới","importance":"normal","giaiDoan":"Hiện thân sau Chu Tước","text":"Sau khi Chu Tước tới, gần trăm người hiện ra trên bầu trời với sáu người tóc trắng đứng đầu.","anchor":"Trên bầu trời, sau khi Chu Tước tới, lại đi ra gần trăm người."}]},"capNhatToi":"@c1005","nguon":["@c1005"]},{"id":"xuat-tru-quoc","name":"Xuất Trứ Quốc","cn":"出储国","type":"tu-chan-quoc","typeLabel":"Tu chân quốc","diaBan":"Liên Minh Tinh Vực","nhanVatChinh":[],"blurb":"Xuất Trứ Quốc là Bát cấp tu chân quốc thuộc Liên Minh Tinh Vực, sở hữu lực lượng gần như bảo tồn hoàn hảo. Cùng Lô Địch Quốc, thế lực này tuyên bố độc lập sau khi Tổng bộ Tu Chân Liên Minh mai danh ẩn tích, vươn lên thành một trong bốn thế lực mạnh nhất mới nổi.","detail":"Xuất Trứ Quốc là một trong hai Bát cấp tu chân quốc (cùng Lô Địch Quốc) tuyên bố độc lập khỏi Tu Chân Liên Minh sau khoảng một năm rưỡi Tổng bộ không có động tĩnh (@c1015). Nhờ lực lượng gần như được bảo tồn hoàn hảo, quốc gia này được xếp vào hàng bốn thế lực mạnh nhất mới nổi của Liên Minh Tinh Vực.","quyMo":"Bát cấp tu chân quốc","trangThai":"Độc lập","tabs":{"tienTrinh":[{"chuong":"@c1015","loai":"lap","importance":"major","giaiDoan":"Tuyên bố độc lập","trangThaiMoc":"Độc lập","text":"Cùng Lô Địch Quốc tuyên bố độc lập khỏi Tu Chân Liên Minh, trở thành một trong bốn thế lực mạnh nhất mới nổi.","anchor":"hai Bát cấp tu chân quốc: Xuất Trứ Quốc và Lô Địch Quốc"}]},"nguon":["@c1015"],"uyLuc":"Lực lượng gần như bảo tồn hoàn hảo, xếp vào hàng bốn thế lực mạnh nhất mới nổi.","dacDiem":"Bát cấp tu chân quốc thuộc Liên Minh Tinh Vực với lực lượng gần như bảo tồn hoàn hảo.","congNang":["Tuyên bố độc lập khỏi Tu Chân Liên Minh cùng Lô Địch Quốc, trở thành một trong bốn thế lực mạnh nhất mới nổi @c1015"]},{"id":"lo-dich-quoc","name":"Lô Địch Quốc","cn":"炉涤国","type":"tu-chan-quoc","typeLabel":"Tu chân quốc","diaBan":"Liên Minh Tinh Vực","nhanVatChinh":[],"blurb":"Lô Địch Quốc là Bát cấp tu chân quốc thuộc Liên Minh Tinh Vực. Cùng Xuất Trứ Quốc, thế lực này tuyên bố độc lập khỏi Tu Chân Liên Minh khi liên minh không có động tĩnh, giữ được lực lượng gần như bảo tồn hoàn hảo.","detail":"Lô Địch Quốc là một trong hai Bát cấp tu chân quốc tuyên bố độc lập khỏi Tu Chân Liên Minh, với lực lượng gần như bảo tồn hoàn hảo. Được xếp vào một trong bốn thế lực mạnh nhất mới nổi trong Liên Minh Tinh Vực. Bước ngoặt của thế lực là việc cùng Xuất Trứ Quốc tuyên bố độc lập khỏi Tu Chân Liên Minh (@c1015).","quyMo":"Bát cấp tu chân quốc","trangThai":"Độc lập","tabs":{"tienTrinh":[{"chuong":"@c1015","loai":"lap","importance":"major","giaiDoan":"Tuyên bố độc lập","trangThaiMoc":"Độc lập","text":"Cùng Xuất Trứ Quốc tuyên bố độc lập khỏi Tu Chân Liên Minh.","anchor":"hai Bát cấp tu chân quốc: Xuất Trứ Quốc và Lô Địch Quốc"}]},"nguon":["@c1015"],"dacDiem":"Bát cấp tu chân quốc, lực lượng gần như bảo tồn hoàn hảo; một trong bốn thế lực mạnh nhất mới nổi trong Liên Minh Tinh Vực."},{"id":"thien-nhan-dien","name":"Thiên Nhân Điện","cn":"天人殿","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Liên Minh Tinh Vực","nhanVatChinh":[],"blurb":"Tân thế lực hình thành do thôn tính ngưng tụ trong bối cảnh Tu Chân Liên Minh không có động tĩnh, một trong bốn thế lực mạnh nhất mới nổi.","detail":"Thế lực mới hình thành bằng cách thôn tính các tông phái nhỏ hơn, nổi lên sau khi Tu Chân Liên Minh Tổng bộ phong bế và không truyền ra mệnh lệnh.","trangThai":"Mới lập","tabs":{"tienTrinh":[{"chuong":"@c1015","loai":"lap","importance":"normal","giaiDoan":"Hình thành do thôn tính","trangThaiMoc":"Mới lập","text":"Thế lực mới hình thành bằng cách thôn tính ngưng tụ, một trong bốn thế lực mạnh nhất mới nổi.","anchor":"phân biệt là Thiên Nhân Điện và Địa Tà Môn"}]},"nguon":["@c1015"]},{"id":"dia-ta-mon","name":"Địa Tà Môn","cn":"地邪门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Liên Minh Tinh Vực","nhanVatChinh":[],"blurb":"Tân thế lực hình thành do thôn tính ngưng tụ, cùng Thiên Nhân Điện là hai thế lực thôn tính mạnh nhất mới nổi.","detail":"Thế lực mới hình thành bằng cách thôn tính các tông phái nhỏ, cùng Thiên Nhân Điện nổi lên như hai thế lực thôn tính mạnh nhất trong Liên Minh Tinh Vực.","trangThai":"Mới lập","tabs":{"tienTrinh":[{"chuong":"@c1015","loai":"lap","importance":"normal","giaiDoan":"Hình thành do thôn tính","trangThaiMoc":"Mới lập","text":"Thế lực mới hình thành bằng cách thôn tính ngưng tụ, cùng Thiên Nhân Điện là hai tân thế lực mạnh nhất.","anchor":"phân biệt là Thiên Nhân Điện và Địa Tà Môn"}]},"nguon":["@c1015"]},{"id":"lien-minh-tong-bo","name":"Liên Minh Tổng bộ","cn":"","type":"faction","typeLabel":"Tổng bộ","diaBan":"Liên Minh Tinh Vực","nhanVatChinh":[],"blurb":"Cơ quan đầu não của Liên Minh Tinh Vực, ban hành phong mệnh nhằm vào Vương Lâm.","detail":"Liên Minh Tổng bộ là trung khu quyền lực của Liên Minh Tinh Vực. Đã ban hành một đạo phong mệnh nhằm vào Vương Lâm, khiến nhiều kẻ lẻn vào phạm vi Tứ Thánh Tông nhưng đều bị tiêu diệt.","nguon":["@c1017"]},{"id":"xuat-van-tong","name":"Xuất Vân Tông","cn":"","aliases":["Xuất Vân Quốc"],"type":"tu-chan-quoc","typeLabel":"Tu chân quốc","diaBan":"Trung tâm Liên Minh Tinh Vực","nhanVatChinh":["Mặc Trí","Lão giả đầu bạc Xuất Vân Tông"],"blurb":"Bát cấp tu chân quốc, thế lực cường đại nhất trong tứ phương trung tâm Liên Minh Tinh Vực, nắm hơn mười tinh cầu, chủ tinh là tổng bộ Xuất Vân Tông.","detail":"Xuất Vân Quốc dùng Xuất Vân Tông làm chủ. Thế lực cường đại nhất trong tứ phương trung tâm Liên Minh, nắm hơn mười tinh cầu. Khi tân Thánh Hoàng Chu Tước xuất hiện, sư tôn Mặc Trí chuẩn bị lễ vật cực kỳ trọng hậu gồm cực phẩm tiên đan, tiên đan, tiên bảo và đầu tinh hồn quý giá để đi hạ lễ, coi việc giao hảo với tân Thánh Hoàng cực kỳ trọng yếu.","quyMo":"Bát cấp tu chân quốc, hơn mười tinh cầu","nguonGoc":"Trung tâm Liên Minh Tinh Vực","thanhVien":[{"ten":"Mặc Trí","chucVu":"Đệ tử","tuChuong":"@c1020","trangThai":"hoat-dong"},{"ten":"Lão giả đầu bạc Xuất Vân Tông","chucVu":"Sư tôn (trưởng bối)","tuChuong":"@c1020","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c1020","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện, chuẩn bị hạ lễ tân Thánh Hoàng","text":"Sư tôn Mặc Trí triệu hoán đệ tử mang lễ vật đi chúc mừng tân Chu Tước Thánh Hoàng.","anchor":"Tinh hồn kia cực kỳ quý giá nhưng hạ lễ của Xuất Vân Quốc ta nhất định phải có thứ đó"}]},"nguon":["@c1020"]},{"id":"loi-than-dien","name":"Lôi Thần Điện","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Phía Bắc và Tây Liên Minh Tinh Vực (đã chiếm)","nhanVatChinh":[],"blurb":"Thế lực tối cao nhất trong đại quân La Thiên tại Liên Minh Tinh Vực sau khi thâu tóm hai mặt phía Bắc và phía Tây.","detail":"Sau khi thành công thâu tóm hai đại khu vực phía Bắc và phía Tây Liên Minh Tinh Vực, Lôi Thần Điện trở thành chưởng khống giả tối cao nhất trong đại quân La Thiên.","tabs":{"tienTrinh":[{"chuong":"@c1020","loai":"nhac-toi","importance":"normal","giaiDoan":"Được nhắc là chưởng khống giả tối cao La Thiên","text":"Được nhắc đến với vai trò chưởng khống giả tối cao nhất trong đại quân La Thiên sau khi chiếm phía Bắc và Tây Liên Minh.","anchor":"Sau khi thành công thâu tóm hai đại khu vực này, Lôi Thần Điện liền trở thành chưởng khống giả tối cao nhất"}]},"nguon":["@c1020"]},{"id":"the-luc-ngoai-nhan","name":"Thế lực ngoại nhân","cn":"","type":"khac","typeLabel":"Thế lực bí ẩn","diaBan":"Bên ngoài Liên Minh Tinh Vực","nhanVatChinh":[],"blurb":"Thế lực bí ẩn đến từ bên ngoài Liên Minh Tinh Vực, đang bí mật hoạt động bên trong, dẫn dụ Văn thú khổng lồ.","detail":"Ba thanh niên mặc hoàng y là thành viên, cầm hương cổ quái dẫn dụ đàn Văn thú khổng lồ giữa Liên Minh Tinh Vực, muốn mang đi gặp trưởng lão lập đại công. Giọng nói hơi khác tu sĩ bản địa.","trangThai":"đang hoạt động bí mật","tabs":{"tienTrinh":[{"chuong":"@c1029","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Ba thanh niên hoàng y dẫn dụ đàn Văn thú khổng lồ giữa Liên Minh Tinh Vực, giọng nói khác tu sĩ bản địa, dường như đến từ bên ngoài.","anchor":"Tiếng nói hắn phát ra lại hơi khác tu sĩ Liên Minh Tinh Vực, dường như đến từ bên ngoài Liên Minh Tinh Vực"}]},"nguon":["@c1029"]},{"id":"thien-mon-tong","name":"Thiên Môn Tông","cn":"天门宗","type":"faction","typeLabel":"Tông phái","diaBan":"Vân Hải tinh vực","nhanVatChinh":["Tô Tân"],"blurb":"Tông phái ở Vân Hải tinh vực, được một tông phái cấp tám hỗ trợ Thanh Quang đại trận, cử đệ tử xâm nhập Liên Minh Tinh Vực dụ bắt Văn Thú.","detail":"Thiên Môn Tông đóng tại Vân Hải tinh vực, đệ tử mặc áo vàng, trưởng lão mặc áo tím. Được một tông phái cấp tám cung cấp Thanh Quang đại trận — trận pháp phòng thủ có thể cản tu sĩ Toái Niết đại viên mãn phải mất vài ngày mới phá nổi. Tại căn cứ biên giới tinh vực có gần trăm đệ tử đang xây dựng trận pháp, do hai trưởng lão áo tím chỉ huy. Ba đệ tử (trong đó có Tô Tân) được cử vào Liên Minh Tinh Vực dò xét, dùng Văn Hồn Hương dụ dẫn hơn mười con Văn Thú khổng lồ mang về. Dù biết Văn Thú có chủ là đại thần thông, hai trưởng lão vẫn quyết giữ vì giá trị quá lớn — Văn Thú vốn là loài nguy hiểm khét tiếng ở Vân Hải, bình thường sống thành đàn mấy trăm đến mấy ngàn con, tông phái cấp sáu cũng phải trả giá lớn mới bắt được. Hai trưởng lão tự tin rằng Thanh Quang đại trận đủ cản đối phương lâu để rút về Vân Hải, và kẻ đuổi vào Vân Hải sẽ “có đi mà không có về”.","nguon":["@c1033"]},{"id":"am-tinh-tong","name":"Ám Tinh Tông","cn":"暗星宗","type":"faction","typeLabel":"Tông phái","diaBan":"","nhanVatChinh":[],"blurb":"Tông phái sở hữu Thiên Suy Dịch quý hiếm, một bình có thể đổi bằng một con ấu trùng Văn Thú Vương.","detail":"Được nhắc đến trong bối cảnh giá trị Văn Thú — Ám Tinh Tông sở hữu loại chất lỏng cực kì quý hiếm gọi là Thiên Suy Dịch, một bình có thể đổi lấy một con ấu trùng Văn Thú Vương.","nguon":["@c1033"]}]};
